async (params, browser) => {
  // Open Airtable table
  await browser.open(`${params.table_url}`)

  // Wait for grid to load
  await browser.waitForSelector('.dataRow, [data-rowindex], .headerRow', 15000)

  // Let grid fully render
  await browser.wait(2000)

  // Click add row button
  await browser.click('.addRowButton, [aria-label="Add row"], [data-testid="add-row-button"], .newRowButton')

  // Wait for new row to appear
  await browser.wait(1500)

  // Fill in field values for new record
  const result = await browser.evaluate(`const fields = JSON.parse(params.field_values); const headers = []; document.querySelectorAll('.headerRow .header, .columnHeader, [data-columnid] .header, [role="columnheader"]').forEach(h => { headers.push(h.textContent?.trim() || ''); }); const lastRow = document.querySelector('.dataRow:last-child, [data-rowindex]:last-child, [role="row"]:last-child'); if (!lastRow) throw new Error('Could not find newly created row'); const filledFields = []; for (const [fieldName, value] of Object.entries(fields)) { const colIndex = headers.findIndex(h => h.toLowerCase() === fieldName.toLowerCase()); if (colIndex === -1) { filledFields.push({ field: fieldName, status: 'column_not_found' }); continue; } const cells = lastRow.querySelectorAll('.cell, [data-columnid], [role="gridcell"]'); const targetCell = cells[colIndex]; if (!targetCell) { filledFields.push({ field: fieldName, status: 'cell_not_found' }); continue; } targetCell.click(); await new Promise(r => setTimeout(r, 500)); const input = targetCell.querySelector('.cellInput, [contenteditable="true"], input, textarea') || document.activeElement; if (input) { if (input.contentEditable === 'true') { input.textContent = String(value); input.dispatchEvent(new Event('input', { bubbles: true })); } else { const nativeSet = Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value').set || Object.getOwnPropertyDescriptor(window.HTMLTextAreaElement.prototype, 'value').set; nativeSet.call(input, String(value)); input.dispatchEvent(new Event('input', { bubbles: true })); input.dispatchEvent(new Event('change', { bubbles: true })); } filledFields.push({ field: fieldName, status: 'filled', value: String(value) }); } else { filledFields.push({ field: fieldName, status: 'no_input_found' }); } await new Promise(r => setTimeout(r, 300)); } document.activeElement?.blur(); return { success: true, fields_processed: filledFields.length, fields: filledFields }`)

  return result
}
